// Build a standalone "drill card" HTML page for a drill markdown/DSL file, with
// the rink diagram generated by the DSL-to-SVG renderer (src/drill-svg.js).
//   node scripts/build-drill-preview.mjs [src.md] [out.html]
import { readFileSync, writeFileSync } from "fs";
import { parseDrill, extractDrill } from "../src/drill-format.js";
import { drillSvg } from "../src/drill-svg.js";

const src = process.argv[2] || "docs/example-drill.md";
const out = process.argv[3] || "docs/example-drill-preview.html";

const dsl = extractDrill(readFileSync(src, "utf8"));
const { title, desc, pieces } = parseDrill(dsl);
const svg = drillSvg(dsl);
const esc = s => String(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

// legend, derived from the pieces
const players = pieces.filter(p => p.kind === "player");
const nets = pieces.filter(p => p.kind === "net");
const legend = [
  ...players.map(p => `<span><span class="dot" style="background:${p.color}"></span>${esc(p.id)}${p.defense ? " — auto-D" : ""}</span>`),
  ...nets.map(p => `<span><span class="dot" style="background:${p.goalie ? "#2f9e57" : p.color}"></span>${esc(p.id)}${p.goalie ? " — net + goalie" : " — net"}</span>`),
  `<span><span class="solid"></span>skating route</span>`,
  `<span><span class="dash"></span>puck path</span>`,
].join("");

// light syntax highlight for the source block
const hi = dsl.split("\n").map(line => {
  if (!line.trim()) return "";
  if (/^(TITLE|DESC)\b/.test(line)) { const [c, ...r] = line.split(/\s+/); return `<span class="meta2">${c}</span> ${esc(r.join(" "))}`; }
  return line.split(/(\s+)/).map((t, i) => {
    if (/^\s+$/.test(t)) return t;
    if (i === 0 && /^(RINK|PIECE|PATH)$/.test(t)) return `<span class="cmd">${t}</span>`;
    if (/=/.test(t)) return `<span class="kv">${esc(t)}</span>`;
    if (/^#[0-9a-fA-F]{3,6}$/.test(t)) return `<span class="kv">${t}</span>`;
    if (/^-?\d/.test(t)) return `<span class="num">${esc(t)}</span>`;
    return esc(t);
  }).join("");
}).join("\n");

const CSS = `
  :root{--ice:#eef5f9;--panel:#fff;--ink:#14202b;--muted:#5c6b78;--line:#d6e2ea;--hair:#e4edf3;--red:#d7263d;--blue:#1f4fa3;--surface:#f6fafd;--mark:#cf3346;--mark-blue:#2f5fb0;--puck:#14171a;--code-bg:#0f1a23;--code-ink:#d9e6f0;--code-dim:#7e93a4;--shadow:0 1px 2px rgba(20,32,43,.06),0 12px 34px -14px rgba(20,32,43,.28);--font-display:800 1em/1 "Helvetica Neue",Helvetica,Arial,sans-serif;--font-body:system-ui,-apple-system,"Segoe UI",Roboto,sans-serif;--font-mono:ui-monospace,"SF Mono","JetBrains Mono",Menlo,Consolas,monospace}
  @media (prefers-color-scheme:dark){:root{--ice:#0d151c;--panel:#131f28;--ink:#e8eff5;--muted:#93a4b2;--line:#26343f;--hair:#1c2831;--red:#ff5a6a;--blue:#5f92e2;--surface:#16232d;--mark:#e2475a;--mark-blue:#4f7fd6;--puck:#cdd8e2;--code-bg:#0a1219;--code-ink:#d3e2ee;--code-dim:#6f8496;--shadow:0 1px 2px rgba(0,0,0,.4),0 18px 44px -18px rgba(0,0,0,.7)}}
  :root[data-theme="light"]{--ice:#eef5f9;--panel:#fff;--ink:#14202b;--muted:#5c6b78;--line:#d6e2ea;--hair:#e4edf3;--red:#d7263d;--blue:#1f4fa3;--surface:#f6fafd;--mark:#cf3346;--mark-blue:#2f5fb0;--puck:#14171a;--code-bg:#0f1a23;--code-ink:#d9e6f0;--code-dim:#7e93a4;--shadow:0 1px 2px rgba(20,32,43,.06),0 12px 34px -14px rgba(20,32,43,.28)}
  :root[data-theme="dark"]{--ice:#0d151c;--panel:#131f28;--ink:#e8eff5;--muted:#93a4b2;--line:#26343f;--hair:#1c2831;--red:#ff5a6a;--blue:#5f92e2;--surface:#16232d;--mark:#e2475a;--mark-blue:#4f7fd6;--puck:#cdd8e2;--code-bg:#0a1219;--code-ink:#d3e2ee;--code-dim:#6f8496;--shadow:0 1px 2px rgba(0,0,0,.4),0 18px 44px -18px rgba(0,0,0,.7)}
  *{box-sizing:border-box}
  body{margin:0;background:var(--ice);color:var(--ink);font-family:var(--font-body);line-height:1.6;-webkit-font-smoothing:antialiased}
  .wrap{max-width:940px;margin:0 auto;padding:clamp(28px,5vw,64px) clamp(18px,4vw,40px) 80px}
  .eyebrow{display:inline-flex;align-items:center;gap:8px;font:700 12px/1 var(--font-body);letter-spacing:.16em;text-transform:uppercase;color:var(--muted)}
  .eyebrow .rule{width:26px;height:2px;background:var(--red);border-radius:2px}
  h1{font:var(--font-display);font-size:clamp(32px,6vw,56px);letter-spacing:-.01em;text-transform:uppercase;text-wrap:balance;margin:16px 0 0;line-height:1}
  .lede{max-width:62ch;margin:14px 0 0;font-size:clamp(16px,2.4vw,19px)}
  .card{margin-top:clamp(26px,4vw,40px);background:var(--panel);border:1px solid var(--line);border-radius:16px;box-shadow:var(--shadow);overflow:hidden}
  .card-head{display:flex;align-items:baseline;justify-content:space-between;gap:12px;flex-wrap:wrap;padding:16px 20px;border-bottom:1px solid var(--hair)}
  .card-head .t{font:700 13px/1 var(--font-body);letter-spacing:.12em;text-transform:uppercase;color:var(--muted)}
  .card-head .meta{font:500 13px/1 var(--font-mono);color:var(--muted);font-variant-numeric:tabular-nums}
  .rinkbox{padding:clamp(14px,3vw,26px)}
  svg.rink{display:block;width:100%;height:auto}
  .legend{display:flex;flex-wrap:wrap;gap:8px 20px;padding:4px 22px 20px;font:500 13px/1.2 var(--font-body);color:var(--muted)}
  .legend span{display:inline-flex;align-items:center;gap:8px}
  .legend .dot{width:12px;height:12px;border-radius:50%;flex:none}
  .legend .dash{width:20px;height:0;border-top:2px dashed var(--puck);flex:none}
  .legend .solid{width:20px;height:0;border-top:2.5px solid var(--red);flex:none}
  .src-h{margin:42px 0 0;font:700 13px/1 var(--font-body);letter-spacing:.14em;text-transform:uppercase;color:var(--muted)}
  .src-note{max-width:62ch;margin:10px 0 16px;color:var(--muted);font-size:15px}
  .src-note code{font-family:var(--font-mono);font-size:.92em;color:var(--ink);background:var(--surface);padding:1px 6px;border-radius:5px;border:1px solid var(--line)}
  .code{background:var(--code-bg);border-radius:14px;box-shadow:var(--shadow);overflow:hidden;border:1px solid rgba(255,255,255,.04)}
  .code-bar{display:flex;align-items:center;gap:10px;padding:11px 16px;border-bottom:1px solid rgba(255,255,255,.07)}
  .code-bar .lang{font:700 11px/1 var(--font-mono);letter-spacing:.1em;text-transform:uppercase;color:#eef5f9;background:var(--red);padding:4px 8px;border-radius:5px}
  .code-bar .file{font:500 13px/1 var(--font-mono);color:var(--code-dim)}
  pre{margin:0;padding:18px 20px;overflow-x:auto;font:500 13.5px/1.65 var(--font-mono);color:var(--code-ink);font-variant-numeric:tabular-nums;tab-size:2}
  pre .cmd{color:#8fd0ff;font-weight:700}
  pre .meta2{color:#ffd06a}
  pre .kv{color:#9be6a6}
  pre .num{color:var(--code-dim)}
  .foot{margin-top:40px;padding-top:18px;border-top:1px solid var(--line);color:var(--muted);font-size:14px}
  .foot code{font-family:var(--font-mono);color:var(--ink)}`;

const html = `<title>${esc(title)} — DrillBoard drill card</title>
<style>${CSS}</style>
<div class="wrap">
  <header>
    <span class="eyebrow"><span class="rule"></span>DrillBoard · Markdown drill card</span>
    <h1>${esc(title)}</h1>
    <p class="lede">${esc(desc)}</p>
  </header>
  <section class="card" aria-label="Rink diagram">
    <div class="card-head"><span class="t">Full sheet</span><span class="meta">${players.length} skater${players.length === 1 ? "" : "s"} · rendered from the DSL</span></div>
    <div class="rinkbox">${svg}</div>
    <div class="legend">${legend}</div>
  </section>
  <h2 class="src-h">The source</h2>
  <p class="src-note">The rink above is drawn automatically from this fenced <code>drill</code> block by <code>src/drill-svg.js</code>. Paste the block into DrillBoard (<b>☰ → Text editor → Apply</b>) or <b>Load</b> the file and it plays.</p>
  <div class="code">
    <div class="code-bar"><span class="lang">drill</span><span class="file">${esc(src.split("/").pop())}</span></div>
    <pre><code>${hi}</code></pre>
  </div>
  <p class="foot">Diagram generated by the DSL-to-SVG renderer — change the drill text and re-run <code>scripts/build-drill-preview.mjs</code> to redraw. See <code>docs/drill-dsl.md</code> for the format.</p>
</div>
`;

writeFileSync(out, html);
console.log("wrote", out, `(${html.length} bytes)`);
